patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -1,10 +1,10 @@
 module mux_4to1(
   input [7:0] in_a, in_b, in_c, in_d,
   input [1:0] sel,
   output reg [7:0] out
 );

-  always @(sel)
+  always @(sel or in_a or in_b or in_c or in_d)
   begin
     case(sel)
       2'b00: out = in_a;
       2'b01: out = in_b;
       2'b10: out = in_c;
       2'b11: out = in_d;

before_code:
module mux_4to1(
  input [7:0] in_a, in_b, in_c, in_d,
  input [1:0] sel,
  output reg [7:0] out
);

  always @(sel)
  begin
    case(sel)
      2'b00: out = in_a;
      2'b01: out = in_b;
      2'b10: out = in_c;
      2'b11: out = in_d;
      default: out = 8'b0;
    endcase
  end

endmodule

after_code:
module mux_4to1(
  input [7:0] in_a, in_b, in_c, in_d,
  input [1:0] sel,
  output reg [7:0] out
);

  always @(sel or in_a or in_b or in_c or in_d)
  begin
    case(sel)
      2'b00: out = in_a;
      2'b01: out = in_b;
      2'b10: out = in_c;
      2'b11: out = in_d;
      default: out = 8'b0;
    endcase
  end

endmodule
